parameters.jsCode:
const items = $input.all();
const track = items.map((item) => {
  let trackType = "";
  if (item?.json?.body?.loanAmount <= 15000) {
    trackType = "Guardian Automated Track";
  } else {
    trackType = "Hu";
  }
  return { ...item.json, track: trackType };
});

return track;

// 1. Safely grab incoming data object
const rawInput = $input.first().json;

// Check if we are in bypass/test mode where data is already an object containing a 'body'
const isDirectWebhookData = rawInput.body && typeof rawInput.body === 'object';

let parsed = {};
let aiResponse = '';

if (!isDirectWebhookData) {
  // Scenario A: Standard AI response parsing path
  aiResponse = rawInput.text || rawInput.output || rawInput.content || '';

  if (!aiResponse && rawInput.message) {
    aiResponse = rawInput.message.content || rawInput.message.text || '';
  }

  if (!aiResponse) {
    for (const key in rawInput) {
      if (typeof rawInput[key] === 'string' && rawInput[key].trim().length > 0) {
        aiResponse = rawInput[key];
        break;
      }
    }
  }

  if (typeof rawInput === 'string') {
    aiResponse = rawInput;
  }

  if (!aiResponse || aiResponse.trim() === "") {
    throw new Error('AI Node returned no text. Keys available: ' + Object.keys(rawInput).join(', '));
  }

  // Extract JSON payload using your regex
  const jsonMatch = aiResponse.match(/\{[\s\S]*\}/);
  if (!jsonMatch) {
    throw new Error('No valid JSON brackets found. Raw response text was: ' + aiResponse);
  }

  try {
    parsed = JSON.parse(jsonMatch[0]);
  } catch (e) {
    throw new Error('JSON parsing failed: ' + e.message);
  }
}

// 2. Fetch background webhook payload data securely 
// It will look at the explicit node reference OR fallback to the current input if running directly.
let webhookData = {};
try {
  webhookData = $('Webhook – Incoming Lead').first().json.body || {};
} catch (err) {
  webhookData = rawInput.body || {};
}

// 3. Fallback text generation if the AI node was bypassed 
const finalTrack = rawInput.track || (webhookData.loanAmount <= 15000 ? "Guardian Automated Track" : "Hunter Board Review Track");
const emailSummary = parsed.farmer_email || `Appraisal: ${webhookData.name || 'Unknown'} (${webhookData.occupation || 'N/A'} at ${webhookData.location || 'N/A'}) requests KES ${webhookData.loanAmount || 0} (${finalTrack}). Weekly Revenue: KES ${webhookData.weeklyRevenue || 0}.`;
const smsSummary = parsed.sms_code_payload || `UJIMA: Habari ${webhookData.name || 'Applicant'}! Loan of KES ${webhookData.loanAmount || 0} is routing to ${finalTrack}. Ref: UJ-${Math.floor(100000 + Math.random() * 900000)}`;

// 4. Return structured clean tracking data schema
return [{
  json: {
    farmer_email: emailSummary,
    sms_code_payload: smsSummary,
    applicant_name: webhookData.name || 'Unknown',
    applicant_phone: webhookData.phone || '',
    applicant_location: webhookData.location || 'Unknown',
    applicant_occupation: webhookData.occupation || 'Unknown',
    weekly_revenue: webhookData.weeklyRevenue || 0,
    dependents: webhookData.dependents || 0,
    peak_months: Array.isArray(webhookData.peakMonths) ? webhookData.peakMonths.join(', ') : '',
    lean_months: Array.isArray(webhookData.leanMonths) ? webhookData.leanMonths.join(', ') : '',
    loan_amount: webhookData.loanAmount || 0,
    loan_purpose: webhookData.loanPurpose || '',
    timestamp: webhookData.timestamp || new Date().toISOString()
  }
}];
